-- ─────────────────────────────────────────────────────────────────────────────
-- Seed: badges + mastery checks (generated by scripts/generate-gamification-seed.ts).
-- Run AFTER 20260529120000_gamification_schema.sql. Idempotent: deterministic
-- uuid v5 ids + ON CONFLICT upserts. Content only; never touches user tables.
-- ─────────────────────────────────────────────────────────────────────────────

begin;

insert into badge_definitions
  (id, slug, name, description, icon, tier, criteria_type, criteria_config, points_reward, sort_order, is_published) values
  ($lum$94ea86b2-1a38-560e-8953-dd5b75690121$lum$::uuid, $lum$first-steps$lum$, $lum$First Steps$lum$, $lum$You finished your first lesson. The hard part is starting, and you just did it.$lum$, $lum$footprints$lum$, $lum$bronze$lum$, $lum$lessons_completed_total$lum$, $lum${"count":1}$lum$::jsonb, 0, 0, true),
  ($lum$21c17c92-f1b7-56b5-b4df-9db95f25196b$lum$::uuid, $lum$foundations-cleared$lum$, $lum$Foundations Cleared$lum$, $lum$Every lesson in Foundations, done. You have the base the rest of the course builds on.$lum$, $lum$flag$lum$, $lum$silver$lum$, $lum$module_completed$lum$, $lum${"module_slug":"foundations"}$lum$::jsonb, 100, 1, true),
  ($lum$0c6e2f41-d066-5c0d-be8a-2933927e430b$lum$::uuid, $lum$module-master$lum$, $lum$Module Master$lum$, $lum$You tested out of a whole module with a check. You earned the skip.$lum$, $lum$crown$lum$, $lum$gold$lum$, $lum$module_mastered_via_check$lum$, $lum${}$lum$::jsonb, 50, 2, true),
  ($lum$2eb11eed-b66f-553a-ad3b-fd30630d3fe5$lum$::uuid, $lum$test-out-ace$lum$, $lum$Test-Out Ace$lum$, $lum$A perfect score on a placement check. Not a single question missed.$lum$, $lum$sparkles$lum$, $lum$gold$lum$, $lum$check_aced$lum$, $lum${}$lum$::jsonb, 50, 3, true),
  ($lum$212d2850-723e-58a0-9944-eacee39d02e9$lum$::uuid, $lum$week-one$lum$, $lum$Week One$lum$, $lum$Seven days in a row. You are building a habit, not just taking a course.$lum$, $lum$flame$lum$, $lum$bronze$lum$, $lum$streak_days$lum$, $lum${"days":7}$lum$::jsonb, 25, 4, true),
  ($lum$77214049-002f-5b7f-bede-dc09eff7f7ce$lum$::uuid, $lum$consistent$lum$, $lum$Consistent$lum$, $lum$A thirty day streak. This is what mastery actually looks like.$lum$, $lum$flame$lum$, $lum$silver$lum$, $lum$streak_days$lum$, $lum${"days":30}$lum$::jsonb, 100, 5, true),
  ($lum$1b2ce3f1-bbc9-593e-a8d4-69b775989311$lum$::uuid, $lum$quick-study$lum$, $lum$Quick Study$lum$, $lum$Five lessons in a single day. Someone is on a roll.$lum$, $lum$zap$lum$, $lum$silver$lum$, $lum$lessons_completed_in_day$lum$, $lum${"count":5}$lum$::jsonb, 25, 6, true),
  ($lum$88700dd5-618f-5eb5-85b9-a461b9085536$lum$::uuid, $lum$polymath$lum$, $lum$Polymath$lum$, $lum$You completed lessons across all six modules. A genuinely broad foundation.$lum$, $lum$compass$lum$, $lum$gold$lum$, $lum$lessons_in_distinct_modules$lum$, $lum${"count":6}$lum$::jsonb, 100, 7, true),
  ($lum$e55f1703-4906-56d7-8109-d1b9d3e6fbc2$lum$::uuid, $lum$centurion$lum$, $lum$Centurion$lum$, $lum$One thousand points earned. Real, measurable progress.$lum$, $lum$gem$lum$, $lum$gold$lum$, $lum$total_points$lum$, $lum${"points":1000}$lum$::jsonb, 0, 8, true),
  ($lum$b1f62da6-83cd-5979-a58e-090186c2b608$lum$::uuid, $lum$credentialed$lum$, $lum$Credentialed$lum$, $lum$You earned a verifiable Lumio certificate. The top of the ladder.$lum$, $lum$badge-check$lum$, $lum$gold$lum$, $lum$cert_earned$lum$, $lum${}$lum$::jsonb, 0, 9, true)
on conflict (slug) do update set
  name = excluded.name,
  description = excluded.description,
  icon = excluded.icon,
  tier = excluded.tier,
  criteria_type = excluded.criteria_type,
  criteria_config = excluded.criteria_config,
  points_reward = excluded.points_reward,
  sort_order = excluded.sort_order,
  is_published = excluded.is_published;

insert into mastery_checks
  (id, slug, scope, lesson_id, module_id, level, title, description, question_count, pass_threshold, cooldown_hours, status) values
  ($lum$9398fe3b-c716-5153-8f93-17af48218962$lum$::uuid, $lum$foundations-module-check$lum$, $lum$module$lum$, NULL, $lum$0c46c9ff-099c-5f97-82bd-26f6977da2cb$lum$::uuid, NULL, $lum$Foundations: test out$lum$, $lum$Already comfortable with the basics? Answer these and the whole Foundations module leaves your path, marked complete.$lum$, 8, 0.8, 24, 'published'),
  ($lum$0e6f5d2b-66f4-5b97-9f57-821449ed9c64$lum$::uuid, $lum$beginner-level-check$lum$, $lum$level$lum$, NULL, NULL, $lum$beginner$lum$, $lum$Beginner level: test out$lum$, $lum$Confident with the beginner material across modules? Clear every beginner lesson at once by passing this check.$lum$, 8, 0.8, 24, 'published')
on conflict (slug) do update set
  scope = excluded.scope,
  lesson_id = excluded.lesson_id,
  module_id = excluded.module_id,
  level = excluded.level,
  title = excluded.title,
  description = excluded.description,
  question_count = excluded.question_count,
  pass_threshold = excluded.pass_threshold,
  cooldown_hours = excluded.cooldown_hours,
  status = excluded.status;

insert into mastery_check_questions
  (id, check_id, order_index, type, content, source_block_id) values
  ($lum$1cab0c0b-c4b0-52dc-90d9-8f8270b96917$lum$::uuid, $lum$9398fe3b-c716-5153-8f93-17af48218962$lum$::uuid, 0, $lum$multiple_choice$lum$, $lum${"stem":"You need to know today's exact interest rate to quote a client. Which tool fits?","options":[{"id":"a","label":"Google, because it is a fact with a verifiable source","is_correct":true,"explanation":"Facts that exist in the world and change in real time are Google's job, not a language model's."},{"id":"b","label":"ChatGPT, because it is faster than searching","is_correct":false,"explanation":"A model has a knowledge cutoff and cannot check live values. You would risk a confident wrong number."},{"id":"c","label":"Either one works equally well","is_correct":false}]}$lum$::jsonb, NULL),
  ($lum$d8b4ee2a-94a2-5b69-8c5b-a754bd8b89d7$lum$::uuid, $lum$9398fe3b-c716-5153-8f93-17af48218962$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Which task is the better fit for ChatGPT than for Google?","options":[{"id":"a","label":"Finding what a specific regulation says word for word","is_correct":false},{"id":"b","label":"Restructuring a messy paragraph into a clear one","is_correct":true,"explanation":"Reasoning, synthesis, and generation are what a model is for."},{"id":"c","label":"Checking yesterday's closing stock price","is_correct":false}]}$lum$::jsonb, NULL),
  ($lum$e40cf00e-1cd1-5657-83c2-099bf920143b$lum$::uuid, $lum$9398fe3b-c716-5153-8f93-17af48218962$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"An AI answer cites a study with a precise journal, year, and percentage. What is the right move?","options":[{"id":"a","label":"Trust it, the specificity proves it is real","is_correct":false,"explanation":"Invented citations are often precise in the wrong way. Specificity is not proof."},{"id":"b","label":"Verify the citation before using it","is_correct":true,"explanation":"Suspiciously specific detail is one of the four hallucination tells. Always verify."},{"id":"c","label":"Assume it is false and discard the whole answer","is_correct":false}]}$lum$::jsonb, NULL),
  ($lum$a380670d-3efb-5a33-965d-c226c5b68296$lum$::uuid, $lum$9398fe3b-c716-5153-8f93-17af48218962$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"Why is hallucination described as structural rather than a bug?","options":[{"id":"a","label":"The model predicts plausible-sounding text, so it will invent a plausible answer even when it does not know","is_correct":true,"explanation":"It is how the model works, which is why you verify rather than expect a future fix."},{"id":"b","label":"The servers are overloaded and make mistakes","is_correct":false},{"id":"c","label":"It only happens with old models","is_correct":false}]}$lum$::jsonb, NULL),
  ($lum$2f00eef1-b054-58d5-9ac9-2ed659d907c7$lum$::uuid, $lum$9398fe3b-c716-5153-8f93-17af48218962$lum$::uuid, 4, $lum$fill_blank$lum$, $lum${"template":"The three parts of the framing technique are role, {{1}}, and constraints.","blanks":[{"id":"1","accept":["task","specific task"],"ideal":"task"}],"explanation":"Role plus a specific task plus constraints turns a generic answer into a useful one."}$lum$::jsonb, NULL),
  ($lum$914cabdc-de94-50eb-9d49-4a174f21b326$lum$::uuid, $lum$9398fe3b-c716-5153-8f93-17af48218962$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"What mainly separates a brief from a prompt?","options":[{"id":"a","label":"A brief is just a longer prompt","is_correct":false},{"id":"b","label":"A brief adds context, stakes, examples, and rejection criteria","is_correct":true,"explanation":"You would not hand a collaborator one sentence and expect professional work."},{"id":"c","label":"A brief must always be written by the AI","is_correct":false}]}$lum$::jsonb, NULL),
  ($lum$335ebedb-3b7a-5119-8acf-3c0163ce9063$lum$::uuid, $lum$9398fe3b-c716-5153-8f93-17af48218962$lum$::uuid, 6, $lum$multiple_choice$lum$, $lum${"stem":"What belongs in custom instructions?","options":[{"id":"a","label":"A one-off request for today's specific task","is_correct":false,"explanation":"Task-specific instructions do not belong in persistent settings."},{"id":"b","label":"Persistent identity: who you are, how you want responses, your tone","is_correct":true,"explanation":"Custom instructions are a permanent brief injected before every conversation."},{"id":"c","label":"Your password so the model can log in for you","is_correct":false}]}$lum$::jsonb, NULL),
  ($lum$35e35e71-d82b-5bc6-bf5a-0864072037c0$lum$::uuid, $lum$9398fe3b-c716-5153-8f93-17af48218962$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"Adding good {{1}} criteria to a brief, the things that would make the output bad, is as important as the instructions themselves.","blanks":[{"id":"1","accept":["rejection","reject"],"ideal":"rejection"}],"explanation":"Telling the model what bad looks like is what cuts revision rounds."}$lum$::jsonb, NULL),
  ($lum$d9a66b69-53e6-5a48-a41a-1d2d0da379db$lum$::uuid, $lum$0e6f5d2b-66f4-5b97-9f57-821449ed9c64$lum$::uuid, 0, $lum$multiple_choice$lum$, $lum${"stem":"What is the fastest test for whether to use Google or ChatGPT?","options":[{"id":"a","label":"Ask whether the answer already exists in the world, or needs to be created","is_correct":true,"explanation":"Exists and verifiable goes to Google; created or reasoned through goes to ChatGPT."},{"id":"b","label":"Always start with Google and switch only if it fails","is_correct":false},{"id":"c","label":"Pick whichever tab is already open","is_correct":false}]}$lum$::jsonb, NULL),
  ($lum$99a145b0-32c2-5380-8fce-468d301d6340$lum$::uuid, $lum$0e6f5d2b-66f4-5b97-9f57-821449ed9c64$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You get an AI answer about a very recent event with no hedging. What does that suggest?","options":[{"id":"a","label":"It is likely fabricated or outdated, since recent events sit past the training cutoff","is_correct":true,"explanation":"Confident claims about recent events are one of the four tells."},{"id":"b","label":"It is definitely accurate because it sounds sure","is_correct":false},{"id":"c","label":"Recent events are the model's strongest area","is_correct":false}]}$lum$::jsonb, NULL),
  ($lum$36c28560-59b3-54c5-9da4-7ac877f3e8aa$lum$::uuid, $lum$0e6f5d2b-66f4-5b97-9f57-821449ed9c64$lum$::uuid, 2, $lum$fill_blank$lum$, $lum${"template":"Before pasting AI output into a document with your name on it, you should {{1}} anything you would stake your reputation on.","blanks":[{"id":"1","accept":["verify","check","confirm"],"ideal":"verify"}],"explanation":"Use AI for synthesis where mostly right is fine, but verify the high-stakes claims."}$lum$::jsonb, NULL),
  ($lum$3fb1d07d-7158-5027-a761-ed0fbdb98f1d$lum$::uuid, $lum$0e6f5d2b-66f4-5b97-9f57-821449ed9c64$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"Which prompt is framed best?","options":[{"id":"a","label":"Help me with my email","is_correct":false},{"id":"b","label":"I am a PM at a fintech startup. Write a 5 bullet board summary of Q3, confident in tone but acknowledging the missed retention target.","is_correct":true,"explanation":"Role plus specific task plus constraints."},{"id":"c","label":"Write something about Q3","is_correct":false}]}$lum$::jsonb, NULL),
  ($lum$5748a8ae-930c-5570-af98-1aadf1bc36d3$lum$::uuid, $lum$0e6f5d2b-66f4-5b97-9f57-821449ed9c64$lum$::uuid, 4, $lum$multiple_choice$lum$, $lum${"stem":"In email triage, which type should you usually write entirely yourself?","options":[{"id":"a","label":"Routine status updates and meeting confirmations","is_correct":false},{"id":"b","label":"A difficult conversation or a negotiation where nuance is everything","is_correct":true,"explanation":"Tier 3 work is where the nuance matters and AI should not sign off for you."},{"id":"c","label":"Standard follow-ups","is_correct":false}]}$lum$::jsonb, NULL),
  ($lum$189ed31a-bb8c-5d85-9bbe-db7a1f486b2f$lum$::uuid, $lum$0e6f5d2b-66f4-5b97-9f57-821449ed9c64$lum$::uuid, 5, $lum$fill_blank$lum$, $lum${"template":"A monthly calendar {{1}} reveals whether how you actually spend your time matches your stated priorities.","blanks":[{"id":"1","accept":["audit","review"],"ideal":"audit"}],"explanation":"Most people find a sizable gap between stated priorities and real time spent."}$lum$::jsonb, NULL),
  ($lum$6e7220cd-9e9d-59b2-8505-3d06ed84d761$lum$::uuid, $lum$0e6f5d2b-66f4-5b97-9f57-821449ed9c64$lum$::uuid, 6, $lum$multiple_choice$lum$, $lum${"stem":"Why do rough, messy notes work fine as input to the meeting debrief protocol?","options":[{"id":"a","label":"The model handles abbreviations and fragments well, so you do not need to clean up first","is_correct":true,"explanation":"You extract the value while it is fresh and outsource the formatting."},{"id":"b","label":"You must always format notes perfectly before pasting","is_correct":false},{"id":"c","label":"Messy notes give better answers than clear ones","is_correct":false}]}$lum$::jsonb, NULL),
  ($lum$d244cd14-d7d1-5416-827e-60271c91e258$lum$::uuid, $lum$0e6f5d2b-66f4-5b97-9f57-821449ed9c64$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"What is the point of setting up custom instructions once?","options":[{"id":"a","label":"So you stop re-establishing the same context at the start of every conversation","is_correct":true,"explanation":"A one-time setup makes every later conversation more useful with no extra effort."},{"id":"b","label":"So the model can browse the web for you","is_correct":false},{"id":"c","label":"So you never have to write prompts again","is_correct":false}]}$lum$::jsonb, NULL)
on conflict (id) do update set
  check_id = excluded.check_id,
  order_index = excluded.order_index,
  type = excluded.type,
  content = excluded.content,
  source_block_id = excluded.source_block_id;

commit;
